import { Header } from './js/Header';
import { Search } from './js/Search';
import { Item } from './js/Item';
import { TodoList } from './js/TodoList';
import { Button } from './js/Button';
//import './/App.css'
import React from 'react';

const taskDefault = [
  { text: 'Revisar Examenes', completed: true },
  { text: 'Escribir', completed: true },
  { text: 'Correr', completed: true },
  { text: 'Caminar', completed: false },
]

function App() {
  const [Tasks_n, setTask] = React.useState(taskDefault);
  const numberTaskCompleted = Tasks_n.filter((task) => task.completed).length;
  const totalTasks = Tasks_n.length
  const [SearchValue, setSearchValue] = React.useState("");
  const SearchTodos = Tasks_n.filter((Tasks) => {

    return Tasks_n.text.toLowerCase().includes(SearchValue).toLowerCase();
  });
  const CompletedTask = (text) => {
    const newTask = [...Tasks_n];
    newTask[indexTask].completed = true;
    setTask(newTask);
  };
  const deleteTask = (text) => {
    const indexTask = newTask.findIndex((task) => task.text === text);
    newTask.splice(indexTask, 1);

    setTask(newTask);
  };
  <React.Fragment>

    <Header completed={numberTaskCompleted} total={totalTasks} />
    <ShearchTodos setSearchValue={SearchValue} setSearchValue={setSearchValue} />

    <Search />
    <TodoList>
      {SearchTodos.map(task => (
        <Item
          key={task.text}
          text={task.text}
          completed={task.completed}
          onCompleted={() => CompletedTask(task.text)}
          onDelete={() => deleteTask(task.text)}
        />
      )
      )
      };

    </TodoList>
    <Button />+



  </React.Fragment>

  ;
}
export default App;
